// shortWorkspacePath returns a compact display form of a workspace path.
// Uses … for very deep paths, showing only the last two components.
func shortWorkspacePath(path string) string {
	if path == "" {
		return ""
	}
	parts := strings.Split(strings.TrimRight(path, "/"), string(filepath.Separator))
	if len(parts) > 3 {
		return "…/" + strings.Join(parts[len(parts)-2:], "/")
	}
	return path
}

// jsonPathValue returns a JSON string of {"path": "<path>"} suitable for hx-vals.
func jsonPathValue(path string) string {
	b, err := json.Marshal(map[string]string{"path": path})
	if err != nil {
		return `{"path":""}`
	}
	return string(b)
}

